export const SND_BUDDYIN = "data:audio/mp3;base64,";
export const SND_BUDDYOUT = "data:audio/mp3;base64,";
export const SND_DOOROPEN = "data:audio/mp3;base64,";
export const SND_IMRCV = "data:audio/mp3;base64,";
export const SND_IMSEND = "data:audio/mp3;base64,";


let _audioCtx: AudioContext | null = null;
let _muted = false;

export function toggleMute(): boolean {
  _muted = !_muted;
  return _muted;
}

export function isMuted(): boolean {
  return _muted;
}
const _bufferCache: Record<string, AudioBuffer> = {};

function getAudioCtx() {
  if (!_audioCtx) _audioCtx = new (window.AudioContext || (window as unknown as {webkitAudioContext: typeof AudioContext}).webkitAudioContext)();
  if (_audioCtx.state === "suspended") _audioCtx.resume();
  return _audioCtx;
}

export function unlockAudio() {
  try { getAudioCtx(); } catch(e) {}
}

export function playSound(src: string) {
  if (_muted) return;
  try {
    const ctx = getAudioCtx();
    if (_bufferCache[src]) {
      const s = ctx.createBufferSource();
      s.buffer = _bufferCache[src];
      const g = ctx.createGain();
      g.gain.value = 0.6;
      s.connect(g).connect(ctx.destination);
      s.start(0);
      return;
    }
    // Decode base64 to ArrayBuffer
    const b64 = src.split(",")[1];
    const raw = atob(b64);
    const arr = new Uint8Array(raw.length);
    for (let i = 0; i < raw.length; i++) arr[i] = raw.charCodeAt(i);
    ctx.decodeAudioData(arr.buffer.slice(0), (buf: AudioBuffer) => {
      _bufferCache[src] = buf;
      const s = ctx.createBufferSource();
      s.buffer = buf;
      const g = ctx.createGain();
      g.gain.value = 0.6;
      s.connect(g).connect(ctx.destination);
      s.start(0);
    }, () => {});
  } catch(e) {}
}
